Code:
public int[] fix45(int[] nums) {
    int[] result = new int[nums.length];
    int index = 0;
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 4) {
            result[index++] = 4;
            result[index++] = 5;
            while (nums[i + 1] == 5) i++;
        } else {
            result[index++] = nums[i];
        }
    }
    return result;
}

